using ContosoUniversity;

namespace ContosoUniversity.Tests;

[TestClass]
public class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        var items = new List<int> { 1, 2, 3 };

        var result = new PaginatedList<int>(items, 10, 2, 3);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };

        var result = new PaginatedList<string>(items, 3, 1, 3);

        Assert.AreEqual(3, result.Count);
        CollectionAssert.AreEqual(items, result);
    }

    [TestMethod]
    [DataRow(10, 3, 4)]
    [DataRow(10, 5, 2)]
    [DataRow(1, 1, 1)]
    [DataRow(0, 5, 0)]
    [DataRow(7, 3, 3)]
    [DataRow(6, 3, 2)]
    [DataRow(100, 10, 10)]
    [DataRow(101, 10, 11)]
    public void TotalPages_CalculatedCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        var result = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        Assert.AreEqual(expectedTotalPages, result.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsFalse(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ReturnsTrue_WhenOnSecondPage()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_ReturnsTrue_WhenOnLastPage()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 5, 2);

        Assert.IsTrue(result.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 1, 5);

        Assert.IsTrue(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_ReturnsFalse_WhenOnLastPage()
    {
        var result = new PaginatedList<int>(new List<int>(), 10, 2, 5);

        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_ReturnsFalse_WhenSinglePage()
    {
        var result = new PaginatedList<int>(new List<int>(), 3, 1, 5);

        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage_FirstPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        CollectionAssert.AreEqual(new List<int> { 1, 2, 3, 4, 5 }, result);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage_MiddlePage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 2, 5);

        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        CollectionAssert.AreEqual(new List<int> { 6, 7, 8, 9, 10 }, result);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage_LastPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var result = PaginatedList<int>.Create(source, 4, 5);

        Assert.AreEqual(4, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        CollectionAssert.AreEqual(new List<int> { 16, 17, 18, 19, 20 }, result);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage_LastPagePartial()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();

        var result = PaginatedList<int>.Create(source, 3, 5);

        Assert.AreEqual(3, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        CollectionAssert.AreEqual(new List<int> { 11, 12, 13 }, result);
    }

    [TestMethod]
    public void Create_SinglePageOfResults()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(1, result.TotalPages);
        Assert.AreEqual(3, result.Count);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(source, 1, 5);

        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public class NotificationServiceTests
{
    private NotificationService _svc = null!;

    [TestInitialize]
    public void Setup()
    {
        _svc = new NotificationService();
        DrainQueue(_svc);
    }

    [TestCleanup]
    public void Cleanup()
    {
        DrainQueue(_svc);
        _svc.Dispose();
    }

    private void DrainQueue(NotificationService svc)
    {
        while (svc.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_SetsAllProperties()
    {
        _svc.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_WorksCorrectly()
    {
        _svc.SendNotification("Course", "101", EntityOperation.UPDATE, "teacher");

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("101", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("teacher", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _svc.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_OnOverloadWithDisplayName_DefaultsToSystem()
    {
        _svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInFIFOOrder()
    {
        _svc.SendNotification("A", "1", EntityOperation.CREATE, "user1");
        _svc.SendNotification("B", "2", EntityOperation.UPDATE, "user2");
        _svc.SendNotification("C", "3", EntityOperation.DELETE, "user3");

        var first = _svc.ReceiveNotification();
        var second = _svc.ReceiveNotification();
        var third = _svc.ReceiveNotification();

        Assert.AreEqual("A", first!.EntityType);
        Assert.AreEqual("B", second!.EntityType);
        Assert.AreEqual("C", third!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        var result = _svc.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithDisplayName_ContainsExpectedText()
    {
        _svc.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Update_WithDisplayName_ContainsExpectedText()
    {
        _svc.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Delete_WithDisplayName_ContainsExpectedText()
    {
        _svc.SendNotification("Department", "5", "English", EntityOperation.DELETE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Department 'English' has been deleted", notification.Message);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithoutDisplayName_UsesIdFormat()
    {
        _svc.SendNotification("Student", "42", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
    }

