using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests;

[TestClass]
public class NotificationServiceTests
{
    private NotificationService _svc = null!;

    [TestInitialize]
    public void Setup()
    {
        _svc = new NotificationService();
        DrainQueue(_svc);
    }

    [TestCleanup]
    public void Cleanup()
    {
        DrainQueue(_svc);
        _svc.Dispose();
    }

    private void DrainQueue(NotificationService svc)
    {
        while (svc.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_SetsAllProperties()
    {
        _svc.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_WorksCorrectly()
    {
        _svc.SendNotification("Course", "101", EntityOperation.UPDATE, "teacher");

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("Course", notification.EntityType);
        Assert.AreEqual("101", notification.EntityId);
        Assert.AreEqual("UPDATE", notification.Operation);
        Assert.AreEqual("teacher", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        _svc.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_OnOverloadWithDisplayName_DefaultsToSystem()
    {
        _svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    public void ReceiveNotification_DequeuesInFIFOOrder()
    {
        _svc.SendNotification("A", "1", EntityOperation.CREATE, "user1");
        _svc.SendNotification("B", "2", EntityOperation.UPDATE, "user2");
        _svc.SendNotification("C", "3", EntityOperation.DELETE, "user3");

        var first = _svc.ReceiveNotification();
        var second = _svc.ReceiveNotification();
        var third = _svc.ReceiveNotification();

        Assert.AreEqual("A", first!.EntityType);
        Assert.AreEqual("B", second!.EntityType);
        Assert.AreEqual("C", third!.EntityType);
    }

    [TestMethod]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        var result = _svc.ReceiveNotification();

        Assert.IsNull(result);
    }

    [TestMethod]
    public void GenerateMessage_Create_WithDisplayName_ContainsExpectedText()
    {
        _svc.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

        var notification = _svc.ReceiveNotification();

        Assert.IsNotNull(notification);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
