namespace ContosoUniversity.Tests;

[TestClass]
public class DbInitializerTests
{
    private SchoolContext CreateContext()
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
            .Options;
        return new SchoolContext(options);
    }

    [TestMethod]
    public void Initialize_SeedsStudents_WhenDatabaseIsEmpty()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.IsTrue(context.Students.Any());
    }

    [TestMethod]
    public void Initialize_Seeds8Students()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_Seeds5Instructors()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_Seeds4Departments()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_Seeds7Courses()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_Seeds3OfficeAssignments()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_Seeds8CourseAssignments()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_Seeds11Enrollments()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_DoesNotReseed_WhenStudentsAlreadyExist()
    {
        using var context = CreateContext();

        // Seed once
        DbInitializer.Initialize(context);
        var studentCount = context.Students.Count();
        var courseCount = context.Courses.Count();

        // Seed again - should be idempotent
        DbInitializer.Initialize(context);

        Assert.AreEqual(studentCount, context.Students.Count());
        Assert.AreEqual(courseCount, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        var lastNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
        var expected = new List<string> { "Alexander", "Alonso", "Anand", "Barzdukas", "Justice", "Li", "Norman", "Olivetto" };
        CollectionAssert.AreEqual(expected, lastNames);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectDepartmentNames()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        var names = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
        var expected = new List<string> { "Economics", "Engineering", "English", "Mathematics" };
        CollectionAssert.AreEqual(expected, names);
    }

    [TestMethod]
    public void Initialize_SeedsCorrectCourseTitles()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        var titles = context.Courses.Select(c => c.Title).OrderBy(t => t).ToList();
        var expected = new List<string> { "Calculus", "Chemistry", "Composition", "Literature", "Macroeconomics", "Microeconomics", "Trigonometry" };
        CollectionAssert.AreEqual(expected, titles);
    }

    [TestMethod]
    public void Initialize_DepartmentsHaveInstructors()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        var departments = context.Departments.ToList();
        Assert.IsTrue(departments.All(d => d.InstructorID.HasValue));
    }

    [TestMethod]
    public void Initialize_CoursesHaveDepartments()
    {
        using var context = CreateContext();

        DbInitializer.Initialize(context);

        var courses = context.Courses.ToList();
        var departmentIds = context.Departments.Select(d => d.DepartmentID).ToList();
        Assert.IsTrue(courses.All(c => departmentIds.Contains(c.DepartmentID)));
    }
}

