using System;
using System.Collections.Generic;
using System.Linq;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public class StudentsControllerTests
    {
        private SchoolContext CreateContext(string dbName = null)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        private Student CreateStudent(string lastName = "Doe", string firstName = "John", DateTime? enrollmentDate = null)
        {
            return new Student
            {
                LastName = lastName,
                FirstMidName = firstName,
                EnrollmentDate = enrollmentDate ?? DateTime.Today
            };
        }

        private void SeedStudents(SchoolContext context, int count = 3)
        {
            var students = new List<Student>
            {
                CreateStudent("Alpha", "Anna", new DateTime(2023, 1, 15)),
                CreateStudent("Beta", "Bob", new DateTime(2023, 6, 1)),
                CreateStudent("Charlie", "Carol", new DateTime(2022, 9, 1))
            };
            for (int i = 3; i < count; i++)
            {
                students.Add(CreateStudent($"Student{i}", $"First{i}", new DateTime(2023, 1, 1).AddDays(i)));
            }
            context.Students.AddRange(students);
            context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudentsOrderedByLastName()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Beta", model[1].LastName);
            Assert.AreEqual("Charlie", model[2].LastName);
        }

        [TestMethod]
        public void Index_SortByNameDesc_ReturnsStudentsInDescendingOrder()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Charlie", model[0].LastName);
            Assert.AreEqual("Beta", model[1].LastName);
            Assert.AreEqual("Alpha", model[2].LastName);
        }

        [TestMethod]
        public void Index_SortByDate_ReturnsStudentsOrderedByEnrollmentDate()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Charlie 2022-09-01, Alpha 2023-01-15, Beta 2023-06-01
            Assert.AreEqual("Charlie", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
            Assert.AreEqual("Beta", model[2].LastName);
        }

        [TestMethod]
        public void Index_SortByDateDesc_ReturnsStudentsOrderedByEnrollmentDateDescending()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Beta", model[0].LastName);
            Assert.AreEqual("Alpha", model[1].LastName);
            Assert.AreEqual("Charlie", model[2].LastName);
        }

        [TestMethod]
        public void Index_SearchByLastName_FiltersResults()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Alpha", null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alpha", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Bob", null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Beta", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchStringSetsPageTo1()
        {
            using var context = CreateContext();
            SeedStudents(context, 15);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, "Student", 3) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index(null, "Alpha", null, null) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alpha", model[0].LastName);
        }

        [TestMethod]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            using var context = CreateContext();
            SeedStudents(context, 15);
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, 2) as ViewResult;

            var model = result!.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.PageIndex);
            Assert.IsTrue(model.Count <= 10);
            Assert.IsTrue(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_SetsViewBagProperties()
        {
            using var context = CreateContext();
            SeedStudents(context);
            var controller = new StudentsController(context);

            var result = controller.Index("Date", null, "test", null) as ViewResult;

            Assert.AreEqual("Date", result!.ViewData["CurrentSort"]);
            Assert.AreEqual("test", result.ViewData["CurrentFilter"]);
            Assert.AreEqual("date_desc", result.ViewData["DateSortParm"]);
        }

        [TestMethod]
        public void Index_EmptySortOrder_SetsNameSortParmToNameDesc()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index(null, null, null, null) as ViewResult;

            Assert.AreEqual("name_desc", result!.ViewData["NameSortParm"]);
        }

        [TestMethod]
        public void Index_NameDescSort_SetsNameSortParmToEmpty()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.AreEqual("", result!.ViewData["NameSortParm"]);
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Details(null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            var student = CreateStudent();
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.Details(student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
            Assert.AreEqual("Doe", model.LastName);
        }

        [TestMethod]
        public void Details_NonExistentId_ThrowsInvalidOperationException()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            // The controller uses .Single() which throws when no match found
            Assert.ThrowsException<InvalidOperationException>(() => controller.Details(999));
        }

        [TestMethod]
        public void Details_ValidId_IncludesEnrollmentsWithCourse()
        {
            using var context = CreateContext();
            var dept = new Department { Name = "TestDept", Budget = 1000, StartDate = DateTime.Today };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course { CourseID = 101, Title = "TestCourse", Credits = 3, DepartmentID = dept.DepartmentID };
            context.Courses.Add(course);
            var student = CreateStudent();
            context.Students.Add(student);
            context.SaveChanges();

            var enrollment = new Enrollment { CourseID = 101, StudentID = student.ID, Grade = Grade.A };
            context.Enrollments.Add(enrollment);
            context.SaveChanges();

            var controller = new StudentsController(context);
            var result = controller.Details(student.ID) as ViewResult;

            var model = result!.Model as Student;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Enrollments);
            Assert.AreEqual(1, model.Enrollments.Count);
        }

        #endregion

        #region Create GET Tests

        [TestMethod]
        public void Create_GET_ReturnsViewWithStudentHavingTodaysDate()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Create() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
        }

        #endregion

        #region Create POST Tests

        [TestMethod]
        public void Create_POST_ValidStudent_SavesAndRedirectsToIndex()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = CreateStudent("Smith", "Jane", new DateTime(2023, 9, 1));

            var result = controller.Create(student) as RedirectToActionResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_InvalidModelState_ReturnsView()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            controller.ModelState.AddModelError("LastName", "Required");
            var student = CreateStudent();

            var result = controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(0, context.Students.Count());
        }

        [TestMethod]
        public void Create_POST_MinValueEnrollmentDate_AddsModelError()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = CreateStudent("Test", "User", DateTime.MinValue);

            var result = controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(controller.ModelState.IsValid);
            Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_POST_EnrollmentDateOutOfSqlRange_AddsModelError()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);
            var student = CreateStudent("Test", "User", new DateTime(1000, 1, 1));

            var result = controller.Create(student) as ViewResult;

            Assert.IsNotNull(result);
            Assert.IsFalse(controller.ModelState.IsValid);
            Assert.IsTrue(controller.ModelState.ContainsKey("EnrollmentDate"));
        }

        #endregion

        #region Edit GET Tests

        [TestMethod]
        public void Edit_GET_NullId_ReturnsBadRequest()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)null) as StatusCodeResult;

            Assert.IsNotNull(result);
            Assert.AreEqual(400, result.StatusCode);
        }

        [TestMethod]
        public void Edit_GET_ValidId_ReturnsViewWithStudent()
        {
            using var context = CreateContext();
            var student = CreateStudent();
            context.Students.Add(student);
            context.SaveChanges();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)student.ID) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as Student;
            Assert.IsNotNull(model);
            Assert.AreEqual(student.ID, model.ID);
        }

        [TestMethod]
        public void Edit_GET_NonExistentId_ReturnsNotFound()
        {
            using var context = CreateContext();
            var controller = new StudentsController(context);

            var result = controller.Edit((int?)999) as NotFoundResult;

            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit POST Tests

        [TestMethod]
        public void Edit_POST_ValidStudent_SavesAndRedirectsToIndex()
        {
            var dbName = Guid.NewGuid().ToString();
            using (var seedContext = CreateContext(dbName))
            {
                seedContext.Students.Add(CreateStudent("Original", "Name", new DateTime(2023, 1, 1)));
                seedContext.SaveChanges();
            }

            using var context = CreateContext(dbName);
            var controller = new StudentsController(context);
            var existingStudent = context.Students.First();
            // Detach so we can attach the modified version
            context.Entry(existingStudent).State = EntityState.Detached;

            var updatedStudent = new Student
            {
