    {
        private Mock<IWebHostEnvironment> _mockEnv = null!;
        private Mock<ILogger<CoursesController>> _mockLogger = null!;

        [TestInitialize]
        public void Setup()
        {
            _mockEnv = new Mock<IWebHostEnvironment>();
            _mockEnv.Setup(e => e.WebRootPath).Returns(Path.Combine(Path.GetTempPath(), "wwwroot_test_" + Guid.NewGuid()));
            _mockEnv.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
            _mockLogger = new Mock<ILogger<CoursesController>>();
        }

        private SchoolContext CreateContext(string? dbName = null)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        private Department SeedDepartment(SchoolContext context, string name = "Engineering")
        {
            var dept = new Department
            {
                Name = name,
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            context.Departments.Add(dept);
            context.SaveChanges();
            return dept;
        }

        private Course CreateCourse(int courseId, int departmentId, string title = "Test Course")
        {
            return new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = departmentId
            };
        }

        private IFormFile CreateMockFormFile(string fileName, long length, byte[]? content = null)
        {
            content ??= new byte[length < int.MaxValue ? (int)length : 1024];
            var stream = new MemoryStream(content);
            var mock = new Mock<IFormFile>();
            mock.Setup(f => f.FileName).Returns(fileName);
            mock.Setup(f => f.Length).Returns(length);
            mock.Setup(f => f.OpenReadStream()).Returns(stream);
            mock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => stream.CopyTo(s));
            return mock.Object;
        }

