            context.SaveChanges();
            var controller = new InstructorsController(context);

            var result = controller.Index(null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as InstructorIndexData;
            Assert.IsNotNull(model);
            var instructors = model.Instructors.ToList();
            Assert.AreEqual(3, instructors.Count);
            Assert.AreEqual("Alpha", instructors[0].LastName);
            Assert.AreEqual("Mid", instructors[1].LastName);
            Assert.AreEqual("Zeta", instructors[2].LastName);
