        private Department CreateDepartment(SchoolContext context, string name = "Engineering")
        {
            var dept = new Department
            {
                Name = name,
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            context.Departments.Add(dept);
            context.SaveChanges();
            return dept;
        }

        private Course CreateCourse(SchoolContext context, int courseId, int departmentId, string title = "Test Course")
        {
            var course = new Course
            {
                CourseID = courseId,
                Title = title,
                Credits = 3,
                DepartmentID = departmentId,
                Enrollments = new List<Enrollment>()
            };
            context.Courses.Add(course);
