+
+namespace ContosoUniversity.Tests
+{
+    [TestClass]
+    public class NotificationsControllerTests
+    {
+        private SchoolContext CreateContext(string? dbName = null)
+        {
+            var options = new DbContextOptionsBuilder<SchoolContext>()
+                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
+                .Options;
+            return new SchoolContext(options);
+        }
+
+        private void DrainNotificationQueue()
+        {
+            var service = new NotificationService();
+            while (service.ReceiveNotification() != null) { }
+        }
+
+        [TestInitialize]
+        public void Setup()
+        {
+            DrainNotificationQueue();
+        }
+
+        #region GetNotifications Tests
+
+        [TestMethod]
+        public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsNotNull(result);
+            var json = SerializeJsonResult(result);
+            Assert.IsTrue(json.Contains("\"success\":true") || json.Contains("\"success\": true"));
+        }
+
+        [TestMethod]
+        public void GetNotifications_WithNotifications_ReturnsNotifications()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+            // Use the notification service to enqueue some notifications
+            var service = new NotificationService();
+            service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
+            service.SendNotification("Course", "101", "Test Course", EntityOperation.UPDATE);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsNotNull(result);
+            var json = SerializeJsonResult(result);
+            Assert.IsTrue(json.Contains("\"success\":true") || json.Contains("\"success\": true"));
+        }
+
+        [TestMethod]
+        public void GetNotifications_LimitsTo10Notifications()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+            var service = new NotificationService();
+            for (int i = 0; i < 15; i++)
+            {
+                service.SendNotification("Entity", i.ToString(), $"Entity {i}", EntityOperation.CREATE);
+            }
+
+            var result = controller.GetNotifications();
+
+            Assert.IsNotNull(result);
+            // The queue should still have 5 remaining
+            int remaining = 0;
+            while (service.ReceiveNotification() != null) remaining++;
+            Assert.AreEqual(5, remaining);
+        }
+
+        [TestMethod]
+        public void GetNotifications_ReturnsJsonResult()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+
+            var result = controller.GetNotifications();
+
+            Assert.IsInstanceOfType(result, typeof(JsonResult));
+        }
+
+        #endregion
+
+        #region MarkAsRead Tests
+
+        [TestMethod]
+        public void MarkAsRead_ReturnsSuccessJson()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+
+            var result = controller.MarkAsRead(1);
+
+            Assert.IsNotNull(result);
+            Assert.IsInstanceOfType(result, typeof(JsonResult));
+            var json = SerializeJsonResult(result);
+            Assert.IsTrue(json.Contains("\"success\":true") || json.Contains("\"success\": true"));
+        }
+
+        [TestMethod]
+        public void MarkAsRead_AnyId_ReturnsSuccess()
+        {
+            using var context = CreateContext();
+            var controller = new NotificationsController(context);
+
+            var result = controller.MarkAsRead(999);
+
+            Assert.IsNotNull(result);
+            var json = SerializeJsonResult(result);
+            Assert.IsTrue(json.Contains("\"success\":true") || json.Contains("\"success\": true"));
+        }
+
